function parseAgent(aiJson) {
  let raw = aiJson?.output ?? aiJson?.message ?? aiJson?.text ?? aiJson;
  if (typeof raw === 'object') return raw;
  if (typeof raw !== 'string') return {};
  try {
    return JSON.parse(stripCodeFences(raw));
  } catch (e) {
    console.log('Failed to parse sender extraction:', e.message);
    return {};
  }
}

const senderInfo = parseAgent(senderExtraction);

