const contactEmail = senderInfo.contactEmail || timeData.senderEmail || '';
const contactPhone = senderInfo.contactPhone || '';

// Combine all data
return [{
  json: {
    ...timeData,
    billingName,
    billingAddressFormatted,
    billingAddress: addressObj,
    contactEmail,
    contactPhone,
    senderInfoExtracted: true
  }
}];

